   242	func newDBTruncateCmd(flags *globalFlags) *cobra.Command {
   243		var force bool
   244	
   245		cmd := &cobra.Command{
   246			Use:   "truncate",
   247			Short: "Truncate all tables",
   248			Long:  "Truncate all tables in the database, preserving the SchemaMigrations table. Respects interleave order (child tables first). This is destructive and requires --force.",
   249			Args:  cobra.NoArgs,
   250			RunE: func(cmd *cobra.Command, args []string) (err error) {
   251				ctx := cmd.Context()
   252				cfg := flags.spannerConfig()
   253	
   254				if err := requireDatabaseConfig(cfg); err != nil {
   255					return err
   256				}
   257	
   258				if err := requireDestructiveConfirmation("truncate database", cfg, force); err != nil {
   259					return err
   260				}
   261	
   262				if err := writeProgress(cmd, "Truncating database: %s", cfg.DatabasePath()); err != nil {
   263					return err
   264				}
   265	
   266				client, err := spannerutil.NewClient(ctx, cfg)
   267				if err != nil {
   268					return err
   269				}
   270				defer func() {
   271					if cerr := client.Close(); cerr != nil && err == nil {
   272						err = cerr
   273					}
   274				}()
   275	
   276				// Query table names and their parent relationships from INFORMATION_SCHEMA.
   277				iter := client.Single().Query(ctx, spanner.Statement{
   278					SQL: `SELECT t.TABLE_NAME, COALESCE(t.PARENT_TABLE_NAME, '') AS PARENT_TABLE_NAME
   279						  FROM INFORMATION_SCHEMA.TABLES t
   280						  WHERE t.TABLE_SCHEMA = '' AND t.TABLE_NAME != 'SchemaMigrations'
   281						  ORDER BY t.TABLE_NAME`,
   282				})
   283	
   284				var tables []tableRelation
   285				if err := iter.Do(func(row *spanner.Row) error {
   286					var name, parent string
   287					if err := row.Columns(&name, &parent); err != nil {
   288						return err
   289					}
   290					tables = append(tables, tableRelation{name: name, parent: parent})
   291					return nil
   292				}); err != nil {
   293					return fmt.Errorf("querying tables: %w", err)
   294				}
   295	
   296				// Build deletion order: child tables before parent tables.
   297				ordered := topologicalSort(tables)
   298	
   299				if err := writeProgress(cmd, "Deleting rows from %d table(s)", len(ordered)); err != nil {
   300					return err
   301				}
   302	
   303				// Truncate each table.
   304				for _, name := range ordered {
   305					if err := writeProgress(cmd, "Deleting rows from table: %s", name); err != nil {
   306						return err
   307					}
   308					if _, err := client.ApplyPartitionedDML(ctx, fmt.Sprintf("DELETE FROM `%s` WHERE true", name)); err != nil {
   309						return fmt.Errorf("truncating table %s: %w", name, err)
   310					}
   311				}
   312	
   313				if _, err := fmt.Fprintf(cmd.OutOrStdout(), "Truncated %d tables in %s\n", len(ordered), cfg.DatabasePath()); err != nil {
   314					return err
   315				}
   316				return nil
   317			},
   318		}
   319	
   320		cmd.Flags().BoolVar(&force, "force", false, "confirm destructive database truncate")
   321	
   322		return cmd
   323	}
